noncompliant:
// Loop that only executes once
for (int i = 0; i < 10; i++) {
  printf("Processing item %d\n", i);
  break; // Loop exits immediately
}

// While loop with immediate break
while (condition) {
  doSomething();
  break; // Always breaks on first iteration
}

// Do-while with return
do {
  result = calculate();
  return result; // Always returns on first iteration
} while (condition);

compliant:
// Use if statement instead
if (true) { // or some actual condition
  printf("Processing item 0\n");
}

// Conditional execution
if (condition) {
  doSomething();
}

// Direct assignment/call
result = calculate();
